            sLine = GetNextLine(sLine);

        }
        else if ( !strncmp( sLine, "/FontMatrix", 11 ) )
        {
            strncpy( sBuffer, sLine, 255);
            sBuffer[255] = '\0';

            ReadDoubleArray<6>( (unsigned char*)(sBuffer + 11), 244, m_oTopDict.arrdFontMatrix );
            sLine = GetNextLine( sLine );
        }
        else if ( !strncmp( sLine, "/FontBBox", 9 ) )
        {
            strncpy( sBuffer, sLine, 255);
