	if (true)
	{
		std::string sArg = m_sGlobalVariable;
		if (sArg.empty())
			sArg = "{}";
		NSStringUtils::string_replaceA(sArg, "\\", "\\\\");
		NSStringUtils::string_replaceA(sArg, "\"", "\\\"");

